using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using System.Web; // For HttpUtility.HtmlEncode

namespace YourApplication.Controllers
{
    public class ProductController : Controller
    {
        // In a real application, this would be an injected service/repository
        private readonly List<ProductReview> _reviews = new List<ProductReview>
        {
            new ProductReview { Id = 1, ProductId = 101, UserName = "Alice", Rating = 5, ReviewText = "This product is <b>amazing</b>! I highly recommend it." },
            new ProductReview { Id = 2, ProductId = 101, UserName = "Bob", Rating = 4, ReviewText = "Good quality, but a bit pricey. The <i>packaging</i> was excellent." },
            new ProductReview { Id = 3, ProductId = 102, UserName = "Charlie", Rating = 3, ReviewText = "It's okay. Nothing special." },
        };

        // GET: Product/Details/101
        public IActionResult Details(int id)
        {
            // In a real application, you'd fetch product details here too
            var productReviews = _reviews.Where(r => r.ProductId == id).ToList();
            ViewBag.ProductName = $"Product {id}"; // Placeholder

            return View(productReviews);
        }
    }

    public class ProductReview
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string UserName { get; set; }
        public int Rating { get; set; }
        public string ReviewText { get; set; }
    }
}

// Views/Product/Details.cshtml
@model IEnumerable<YourApplication.Controllers.ProductReview>

@{
    ViewData["Title"] = @ViewBag.ProductName + " Reviews";
}

<h1>@ViewBag.ProductName Reviews</h1>

@if (Model != null && Model.Any())
{
    <div class="reviews-list">
        @foreach (var review in Model)
        {
            <div class="review-item border p-3 mb-3 rounded">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">@review.UserName</h5>
                    <span class="badge bg-primary">Rating: @review.Rating/5</span>
                </div>
                <div class="review-text">
                    @Html.Raw(HttpUtility.HtmlEncode(review.ReviewText)
                        .Replace("&lt;b&gt;", "<b>")
                        .Replace("&lt;/b&gt;", "</b>")
                        .Replace("&lt;i&gt;", "<i>")
                        .Replace("&lt;/i&gt;", "</i>"))
                </div>
            </div>
        }
    </div>
}
else
{
    <p>No reviews yet for @ViewBag.ProductName. Be the first to review!</p>
}

